# a(n) is the length of the finite sequence starting at x_1 = n.
import math
def get_next_x(x):
    """Find the smallest positive integer k such that x + k^2 is a square."""
    if x % 4 == 2:
        return None
    limit = math.isqrt(x)
    if limit * limit == x:
        limit -= 1
    for a in range(limit, 0, -1):
        if x % a == 0:
            b = x // a
            if (b - a) % 2 == 0:
                k = (b - a) // 2
                if k > 0:
                    return k
    return None
def a(n):
    """Compute the number of terms in the sequence starting at n."""
    curr = n
    count = 1
    while True:
        nxt = get_next_x(curr)
        if nxt is None:
            break
        curr = nxt
        count += 1
    return count
